import{_ as p,o as e,c as n,ag as i}from"./chunks/framework.DXGyWiRo.js";const t="/images/uebung006.jpg",m=JSON.parse('{"title":"Übung Lektion 7","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/uebung07.md","filePath":"lektionen/uebung07.md"}'),r={name:"lektionen/uebung07.md"};function s(u,a,d,h,l,o){return e(),n("div",null,[...a[0]||(a[0]=[i('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="ubung-lektion-7" tabindex="-1">Übung Lektion 7 <a class="header-anchor" href="#ubung-lektion-7" aria-label="Permalink to &quot;Übung Lektion 7&quot;">​</a></h1><p>A) Setzen Sie jeweils im Singular und Plural (sofern es keine Eigennamen sind) das direkte Objekt bzw. den Richtungsakkusativ ein:</p><p>1. brāhmaṇas ... yajati (deva, devī, viṣṇu, agni, devatā)</p><p>ब्राह्मणस् ... यजति (देव, देवी, विष्णु, अग्नि, देवता)</p><p>brāhmaṇo devaṃ / devān yajati. brāhmaṇo devīṃ / devīr yajati. brāhmaṇo viṣṇuṃ yajati. brāhmaṇo &#39;gniṃ yajati. brāhmaṇo devatām / devatā yajati.</p><p>ब्राह्मणो देवं यजति । ब्राह्मणो देवान्यजति । ब्राह्मणो देवीं यजते । ब्राह्मनो देवीर्यजति । ब्राह्मणो विष्णुं यजति । ब्राह्मनो ऽग्निं यजति | ब्राह्मणो देवतां यजति । ब्राह्मणो देवता यजति ।</p><p>2. gurus ... khādati (phala)</p><p>गुरुस् ... खादति (फल)</p><p>guruḥ phalṃ / phalāni khādati.</p><p>गुरुः फलं खादति । गुरुः फलानि खादति ।</p><p>3. sādhus ... gacchati (svarga)</p><p>साधुस् ... गच्छति (स्वर्ग)</p><p>sādhuḥ svargaṃ / svargān gacchati.</p><p>साधुः स्वर्गं गच्छति । साधुः स्वर्गान्गच्छति ।</p><p>4. śūdrā ... gacchati (naraka)</p><p>शूद्रा ... गच्छति (नरक)</p><p>sūdro narakaṃ / narakān gacchati.</p><p>शूद्रो नरकं गच्छति । शूद्रो नरकान्गच्छति ।</p><p>5. ... jayati (śūdra)</p><p>... जयति (शूद्र)</p><p>śūdraṃ jayati. śūdrāñ jayati.</p><p>शूद्रं जयति । शूद्रञ्जयति ।</p><p>6. ... labhate (dhenu, paśu, phala)</p><p>... लभते (धेनु, पशु, फल)</p><p>dhenuṃ labhate. dhenūr labhate. paśuṃ labhate. paśūṃḷ labhate. phalaṃ labhate. phalāni labhate.</p><p>धेनुं लभते । धेनूर्लभते । पशुं लभते । पशूंल्लभते । फलं लभते । फलानि लभते॥</p><p>B) Setzen Sie dien entsprechenden Verbformen ein:</p><p>1. sādhuḥ svargam ... (āp, gam, aś)</p><p>साधुः स्वर्गम् ... (आप्, गम्, अश्)</p><p>sādhuḥ svargam āpnoti. sādhuḥ svargaṃ gacchati. sādhuḥ svragam aśnute.</p><p>साधुः स्वर्गमाप्नोति । साधुः स्वर्गं गच्छति । साधुः स्व्रगमश्नुते ।</p><p>2. brāhmaṇaḥ somam ... (su) (2 Formen)</p><p>ब्राह्मणः सोमम् ... (सु)</p><p>brāhmaṇaḥ somaṃ sunoti / sunute.</p><p>ब्राह्मणः सोमं सुनोति । ब्राह्मणः सोमं सुनुते ।</p><p>3. sādhur gurum ... (śru)</p><p>साधुर्गुरुम् ... (श्रु)</p><p>sādhur guruṃ  śṛṇoti.</p><p>साधुर्गुरुं शृणोति ।</p><p>4. devī ... (kup, krudh)</p><p>देवी ... (कुप्, क्रुध्)</p><p>devī kupyati. devī krudhyati.</p><p>देवी कुप्यति । देवी क्रुध्यति ।</p><p>C) Setzen Sie in den Übungssätzen B) Agens, Objekt und Verb in den Plural.</p><p>1. sādhavaḥ svargān āpnuvanti. sādhavaḥ svargān gacchanti. sādhavaḥ svargān aśnuvate.</p><p>साधवः स्वर्गानाप्नुवन्ति । साधवः स्वर्गान्गच्छन्ति । साधवः स्वर्गानश्नुवते ।</p><p>2. brāhmanāḥ somaṃ sunvanti.</p><p>ब्राह्मणाः सोमं सुन्वन्ति ।</p><p>3. sādhavo gurūñ chrṇvanti / śṛṇvanti.</p><p>साधवो गुरूञ्छृण्वन्ति । साधवो गुरूञ्शृण्वन्ति ।</p><p>4. devyaḥ kupyanti. devyaḥ krudhyanti.</p><p>देव्यः कुप्यन्ति । देव्यः क्रुध्यन्ति ।</p><p>D) Setzen Sie ins Ātmanepada:</p><p>1. sunvanti.</p><p>सुन्वन्ति |</p><p>sunvate</p><p>सुन्वते ।</p><p>2. nayanti.</p><p>नयन्ति |</p><p>nayante</p><p>नयन्ते ।</p><p>3. sunoti.</p><p>सुनोति |</p><p>sunute</p><p>सुनुते ।</p><p>4. yajati.</p><p>यजति |</p><p>yajate</p><p>यजते ।</p><p>E) Bilden Sie zu allen bisher gelernten Nomina den Akkusativ (dvitīyā) sg. und pl.</p><p>F) Übersetzen Sie:</p><p>1. narakāṃś ca svargāṃś ca gacchanti.</p><p>नरकांश्च स्वर्गांश्च गच्छन्ति |</p><p>Sie gehen in Himmel und Höllen.</p><p>2. gurūṃs tu śṛṇvanti.</p><p>गुरूंस्तु शृण्वन्ति |</p><p>Sie hören aber auf die Meister.</p><p>3. Śūdras erlangen einen Himmel.</p><p>śūdrāḥ svargam āpnuvanti.</p><p>शूद्राः स्वर्गमाप्नुवन्ति ।</p><p>4. Die Kṣatriyas verehren als Opferherren die Göttinnen mit Opfern.</p><p>kṣatriyā devīr yajante.</p><p>क्षत्रिया देवीर्यजन्ते ।</p><p>5. Vaiśyafrauen verehren Gottheiten mit Opfern.</p><p>vaiśyā devatā yajante.</p><p>वैश्या देवता यजन्ते ।</p><p>6. Der HERR zürnt.</p><p>īśvaraḥ kupyati / īśvaraḥ krudhyati.</p><p>ईश्वरः कुप्यति । ईश्वरः क्रुध्यति ।</p><p>7. śikṣā kalpo vyākaraṇaṃ niruktaṃ chando jyotiṣam aṅgāni. (Nach Kauṭilīya-arthaṣāstra 1.3.3.) Erklärung: chando = Nom,, Akk. sg. zu chandas n.)</p><p>शिक्षा कल्पो व्याकरणं निरुक्तं छन्दो ज्योतिषमङ्गानि |</p><p>Die Hilfswissenschaften der Vedistik sind: Aussprachelehre, Ritualistik, Grammatik, Worterklärung, Metrik, Kalenderlehre.</p><p>8. Welchem Gott opfert dieser Brahmane?</p><p>ayaṃ brāhmaṇaḥ kaṃ devaṃ yajati / yajate?</p><p>अयं ब्राह्मणः कं देवं यजति / यजते ।</p><p>9. Was kaut dieser heilige Mann?</p><p>ayaṃ sādhuḥ kiṃ khādati?</p><p>अयं साधुः किं खादति ।</p><p>10. Was pressen diese (hier) aus?</p><p>ete kiṃ sunvanti / sunvate?</p><p>एते किं सुन्वन्ति / सुन्वते ।</p><p>11. Er ist der Lehrer. Auf ihn hört man (= hören sie).</p><p>sa guruḥ. enaṃ śṛṇvanti.</p><p>स गुरुः । एनं शृण्वन्ति ॥</p><p><img src="'+t+'" alt=""><br> Abb.: sa guruḥ. enaṃ śṛṇvanti. = स गुरुः । एनं शृण्वन्ति ॥<br> Svāmī Vivekānanda (স্বামী বিবেকানন্দ) in Chicago, 1893<br> [Bildquelle: Wikipedia. Public domain]</p>',106)])])}const v=p(r,[["render",s]]);export{m as __pageData,v as default};
